mapper.select:
SELECT stat_date AS statDate, project_id AS projectId, investment_manager_id AS investmentManagerId, format_type AS formatType, intention_count AS intentionCount, intention_signed AS intentionSigned, new_intention AS newIntention, contract_count AS contractCount, contract_amount AS contractAmount, contract_area AS contractArea, new_contract AS newContract, conversion_rate AS conversionRate, avg_rent_price AS avgRentPrice FROM rpt_investment_daily WHERE is_deleted = 0 AND stat_date = #{statDate} AND format_type = ''
AND investment_manager_id = #{managerId}
AND investment_manager_id = 0
AND project_id = #{projectId}
ORDER BY contract_amount DESC
